import React, { useState, useEffect } from "react";
import axios from "axios";

const Dashboard = () => {
  const [lots, setLots] = useState([]);
  const [error, setError] = useState("");

  useEffect(() => {
    fetchLots();
  }, []);

  const fetchLots = async () => {
    try {
      const response = await axios.get("http://localhost:5001/api/lots");
      setLots(response.data);
    } catch (error) {
      console.error("Error fetching lots:", error);
      setError("Failed to load lots");
    }
  };

  return (
    <div>
      <h1>Dashboard</h1>

      {/* KPIs */}
      <div className="kpis">
        <div className="kpi">
          <h1>2,000</h1>
          <p>Lots Inspected</p>
        </div>
        <div className="kpi">
          <h1>3,500</h1>
          <p>Samples</p>
        </div>
        <div className="kpi">
          <h1>2.50</h1>
          <p>Avg. Condition Score</p>
        </div>
        <div className="kpi">
          <h1>2.20</h1>
          <p>Avg Quality Score</p>
        </div>
      </div>

      {/* Summary table */}
      <div className="inspectors-list">
        <h3>Current Lots</h3>
        {error && <div className="error-message">{error}</div>}
        <div className="table-container">
          <table>
            <thead>
              <tr>
                <th>Name</th>
                <th>Lot ID</th>
                <th>Department</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {lots.map((lot) => (
                <tr key={lot._id}>
                  <td>{lot.lotNumber}</td>
                  <td>{lot.inspectionType}</td>
                  <td>{lot.status}</td>
                  <td>{lot.inspectorName}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
